import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is target heart rate?", a: "Target heart rate is a training range that helps guide exercise intensity based on your maximum heart rate or heart rate reserve." },
  { q: "How do you calculate maximum heart rate?", a: "A common estimate is 220 minus age. It is simple but can vary by person." },
  { q: "What are the five heart rate training zones?", a: "The five zones are recovery, fat burn, aerobic, threshold, and maximum effort." },
  { q: "What is the Karvonen formula?", a: "The Karvonen formula uses heart rate reserve: Target HR = resting HR + intensity  x  (max HR - resting HR)." },
  { q: "What heart rate zone burns the most fat?", a: "Zone 2 is often called the fat-burn zone, but total fat loss depends on total calories and consistency over time." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const zones = [["Zone 1 Recovery", 50, 60, "Recovery", "Very easy"], ["Zone 2 Fat Burn", 60, 70, "Base endurance", "Easy"], ["Zone 3 Aerobic", 70, 80, "Aerobic fitness", "Moderate"], ["Zone 4 Threshold", 80, 90, "Speed endurance", "Hard"], ["Zone 5 Maximum", 90, 100, "Peak effort", "Very hard"]];

export default function TargetHeartRateCalculator() {
  const [age, setAge] = useState(30);
  const [resting, setResting] = useState(60);
  const result = useMemo(() => {
    const max = 220 - age;
    const reserve = max - resting;
    return { max, rows: zones.map(([name, low, high, goal, effort]) => ({ name, low: Number(low), high: Number(high), bpm: [max * Number(low) / 100, max * Number(high) / 100], karvonen: [resting + reserve * Number(low) / 100, resting + reserve * Number(high) / 100], goal, effort })) };
  }, [age, resting]);
  const age30Max = 190;
  return (
    <>
      <SEOHead title="Free Target Heart Rate Calculator Online - Calculate Your Heart Rate Zones Instantly | CalcHive" description="Free online target heart rate calculator. Calculate your maximum heart rate, all five training zones and Karvonen formula zones for any age instantly. 100% free, no signup required." canonical="/target-heart-rate-calculator" keywords="free target heart rate calculator, heart rate zone calculator free online, max heart rate calculator free, cardio heart rate calculator free, Karvonen formula calculator free" category="Health Calculators" breadcrumbName="Free Target Heart Rate Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Target Heart Rate Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate maximum heart rate, five training zones, and Karvonen heart-rate reserve zones.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Resting heart rate</label><input type="number" value={resting} onChange={(e) => setResting(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Maximum Heart Rate</p><p className="text-5xl sm:text-6xl font-black text-white">{result.max} bpm</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Zone 2 range</p><p className="text-lg font-extrabold">{Math.round(result.rows[1].bpm[0])}-{Math.round(result.rows[1].bpm[1])} bpm</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Karvonen Zone 2</p><p className="text-lg font-extrabold">{Math.round(result.rows[1].karvonen[0])}-{Math.round(result.rows[1].karvonen[1])} bpm</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Target Heart Rate Zones for Free</h2><p className="text-muted-foreground leading-relaxed">Estimate max heart rate as 220 minus age, then multiply by each intensity percentage. Karvonen zones add resting heart rate into the calculation.</p><h2 className="text-2xl font-bold">What Are the Five Heart Rate Training Zones</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Heart Rate Training Zones by Intensity</caption><thead className="bg-muted/60"><tr>{["Zone", "% of Max HR", "BPM for Age 30", "Training Goal", "Perceived Effort"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{zones.map(([name, low, high, goal, effort]) => <tr key={String(name)}><td className="py-2.5 px-3 font-semibold">{name}</td><td className="py-2.5 px-3">{low}-{high}%</td><td className="py-2.5 px-3">{Math.round(age30Max * Number(low) / 100)}-{Math.round(age30Max * Number(high) / 100)}</td><td className="py-2.5 px-3">{goal}</td><td className="py-2.5 px-3">{effort}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Cardio Heart Rate Zone Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/target-heart-rate-calculator" headingLevel="h3" /></main>
    </>
  );
}


